		'second_milestone_amount_and_date' => Request::dateComponents('second_milestone_amount_and_date', '1'),
		'stage_2_completion' => Request::dateComponents('stage_2_completion', ''),
		'third_milestone_amount_and_date' => Request::dateComponents('third_milestone_amount_and_date', '1'),
		'stage_3_completion' => Request::dateComponents('stage_3_completion', ''),
		'fourth_milestone_amount_and_date' => Request::dateComponents('fourth_milestone_amount_and_date', '1'),
		'stage_4_completion' => Request::dateComponents('stage_4_completion', ''),
