		'fourth_milestone_amount_and_date' => Request::dateComponents('fourth_milestone_amount_and_date', ''),
		'stage_4_completion' => Request::dateComponents('stage_4_completion', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('summary_table_tdp', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: summary_table_tdp_before_update
	if(function_exists('summary_table_tdp_before_update')) {
		$args = ['old_data' => $old_data];
		if(!summary_table_tdp_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'summary_table_tdp',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="summary_table_tdp_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('summary_table_tdp', $data['selectedID'], calculated_fields()['summary_table_tdp']);

	// hook: summary_table_tdp_after_update
	if(function_exists('summary_table_tdp_after_update')) {
		if($row = getRecord('summary_table_tdp', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!summary_table_tdp_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('summary_table_tdp', $selected_id);
}

